import base64
import gzip
import json
from typing import Any, Dict, List, Optional

COMPRESSED_INVENTORY = ''

InventoryItem = Dict[str, str]

def fallback_svg_url(id: str, path_part: str = "illustration") -> str:
    return f"https://cdn.undraw.co/{path_part}/{id}.svg"

def normalize_inventory_item(item: Any) -> Optional[InventoryItem]:
    if isinstance(item, list) and len(item) >= 2 and isinstance(item[0], str) and isinstance(item[1], str):
        return {"id": item[0], "title": item[1], "svg_url": fallback_svg_url(item[0])}
    if isinstance(item, dict):
        id = item.get("id") or item.get("newSlug")
        title = item.get("title")
        svg_url = item.get("svg_url") or item.get("media")
        if isinstance(id, str) and isinstance(title, str) and isinstance(svg_url, str):
            return {"id": id, "title": title, "svg_url": svg_url}
    return None

def load_inventory() -> Optional[List[InventoryItem]]:
    """Decompress and parse the embedded inventory."""
    if not COMPRESSED_INVENTORY:
        return None
    try:
        compressed_data = base64.b64decode(COMPRESSED_INVENTORY.strip())
        json_data = gzip.decompress(compressed_data).decode('utf-8')
        parsed = json.loads(json_data)
        return [
            normalized
            for item in parsed
            if (normalized := normalize_inventory_item(item)) is not None
        ]
    except Exception:
        return None
